import{_ as e,o as l,c as o,a3 as t}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"❓ 常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/faq.md","filePath":"user-guide/tools/llm-chat/faq.md","lastUpdated":1778221347000}'),i={name:"user-guide/tools/llm-chat/faq.md"};function r(n,a,h,s,d,q){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h1><h2 id="连接与配置" tabindex="-1">连接与配置 <a class="header-anchor" href="#连接与配置" aria-label="Permalink to &quot;连接与配置&quot;">​</a></h2><h3 id="q-为什么发送消息后一直没回复" tabindex="-1">Q: 为什么发送消息后一直没回复？ <a class="header-anchor" href="#q-为什么发送消息后一直没回复" aria-label="Permalink to &quot;Q: 为什么发送消息后一直没回复？&quot;">​</a></h3><p>A: 常见原因和解决方法：</p><ol><li><strong>检查网络连接</strong>：确保你的网络可以访问 AI 服务提供商的 API</li><li><strong>检查 API Key</strong>：进入「设置 → AI 服务配置」确认 API Key 有效且未过期</li><li><strong>检查模型选择</strong>：确认已为 Agent 选择了正确的模型</li><li><strong>查看错误信息</strong>：如果消息内容区域显示红色错误提示（如&quot;请求超时&quot;、&quot;API Key 无效&quot;等），根据提示排查</li><li><strong>超时设置</strong>：在聊天设置 → 请求设置中增加超时时间</li></ol><h3 id="q-如何配置代理" tabindex="-1">Q: 如何配置代理？ <a class="header-anchor" href="#q-如何配置代理" aria-label="Permalink to &quot;Q: 如何配置代理？&quot;">​</a></h3><p>A: 当你的网络需要通过代理访问 AI 服务时：</p><ol><li>进入「设置 → AI 服务配置」</li><li>在对应的服务渠道中配置代理地址（如 <code>127.0.0.1:7897</code>）</li><li>部分服务支持独立的代理设置</li></ol><h2 id="费用与-token" tabindex="-1">费用与 Token <a class="header-anchor" href="#费用与-token" aria-label="Permalink to &quot;费用与 Token&quot;">​</a></h2><h3 id="q-使用-llm-chat-需要付费吗" tabindex="-1">Q: 使用 LLM Chat 需要付费吗？ <a class="header-anchor" href="#q-使用-llm-chat-需要付费吗" aria-label="Permalink to &quot;Q: 使用 LLM Chat 需要付费吗？&quot;">​</a></h3><p>A: 应用本身是免费的。但调用 AI 模型的 API 需要你自己承担费用——你需要准备各 AI 服务商的 API Key 并充值。</p><h3 id="q-怎么控制-token-消耗" tabindex="-1">Q: 怎么控制 Token 消耗？ <a class="header-anchor" href="#q-怎么控制-token-消耗" aria-label="Permalink to &quot;Q: 怎么控制 Token 消耗？&quot;">​</a></h3><p>A: 以下方法可以有效减少 Token 使用：</p><ol><li><strong>缩短 Max Tokens</strong>：在 Agent 参数中设置较小的输出上限</li><li><strong>启用上下文压缩</strong>：长对话后使用压缩节点将历史摘要化</li><li><strong>关闭不需要的处理器</strong>：如不需要世界书或知识库，在管道配置中关闭</li><li><strong>定期创建新会话</strong>：避免单次对话积累过多历史</li></ol><h2 id="功能使用" tabindex="-1">功能使用 <a class="header-anchor" href="#功能使用" aria-label="Permalink to &quot;功能使用&quot;">​</a></h2><h3 id="q-如何导入-sillytavern-角色卡" tabindex="-1">Q: 如何导入 SillyTavern 角色卡？ <a class="header-anchor" href="#q-如何导入-sillytavern-角色卡" aria-label="Permalink to &quot;Q: 如何导入 SillyTavern 角色卡？&quot;">​</a></h3><p>A: 支持导入 PNG 格式的 SillyTavern V2 角色卡：</p><ol><li>在创建 Agent 时选择「导入 SillyTavern 角色卡」</li><li>选择 <code>.png</code> 文件</li><li>系统会自动解析角色信息并创建 Agent</li></ol><h3 id="q-分支太多怎么管理" tabindex="-1">Q: 分支太多怎么管理？ <a class="header-anchor" href="#q-分支太多怎么管理" aria-label="Permalink to &quot;Q: 分支太多怎么管理？&quot;">​</a></h3><p>A: 切换到<strong>对话树图视图</strong>（点击中栏顶部的视图切换按钮），以力导向布局查看所有分支。你还可以：</p><ul><li>使用消息导航器前进/后退浏览</li><li>在树图中拖拽节点调整布局</li><li>删除不需要的分支（点击节点上的删除按钮）</li></ul><h3 id="q-为什么我的消息没有发送出去" tabindex="-1">Q: 为什么我的消息没有发送出去？ <a class="header-anchor" href="#q-为什么我的消息没有发送出去" aria-label="Permalink to &quot;Q: 为什么我的消息没有发送出去？&quot;">​</a></h3><p>A: 可能的原因：</p><ol><li><strong>当前会话正在生成中</strong>：等待当前生成完成后再发送</li><li><strong>快捷键冲突</strong>：确认快捷键设置（<code>Ctrl+Enter</code> 或 <code>Enter</code>）</li><li><strong>输入框为空</strong>：不能发送空白消息</li></ol><h3 id="q-如何撤销误操作" tabindex="-1">Q: 如何撤销误操作？ <a class="header-anchor" href="#q-如何撤销误操作" aria-label="Permalink to &quot;Q: 如何撤销误操作？&quot;">​</a></h3><p>A: 在聊天窗口中使用 <code>Ctrl + Z</code> 撤销最近一次操作，如删除消息、编辑内容等。撤销历史基于当前会话维护。</p><h2 id="数据与隐私" tabindex="-1">数据与隐私 <a class="header-anchor" href="#数据与隐私" aria-label="Permalink to &quot;数据与隐私&quot;">​</a></h2><h3 id="q-我的对话数据存储在哪里" tabindex="-1">Q: 我的对话数据存储在哪里？ <a class="header-anchor" href="#q-我的对话数据存储在哪里" aria-label="Permalink to &quot;Q: 我的对话数据存储在哪里？&quot;">​</a></h3><p>A: 所有对话数据均存储在<strong>本地</strong>：</p><ul><li>应用数据目录下的 <code>AppData</code> 文件夹</li><li>会话以分离的索引和详情文件存储</li><li>Agent 和用户档案有独立的存储目录</li></ul><p>数据不会自动上传到云端。</p><h3 id="q-如何备份我的数据" tabindex="-1">Q: 如何备份我的数据？ <a class="header-anchor" href="#q-如何备份我的数据" aria-label="Permalink to &quot;Q: 如何备份我的数据？&quot;">​</a></h3><p>A: 推荐方法：</p><ol><li><strong>导出 Agent</strong>：在 Agent 编辑器中导出为 JSON 或 ZIP</li><li><strong>导出会话</strong>：将会话导出为 Markdown 或 JSON</li><li><strong>手动备份</strong>：复制 <code>AppData/llm-chat/</code> 目录下的所有文件</li></ol><h3 id="q-导出数据会包含-api-key-吗" tabindex="-1">Q: 导出数据会包含 API Key 吗？ <a class="header-anchor" href="#q-导出数据会包含-api-key-吗" aria-label="Permalink to &quot;Q: 导出数据会包含 API Key 吗？&quot;">​</a></h3><p>A: <strong>不会</strong>。Agent 导出文件仅包含配置信息（模型 ID、预设消息等），不会包含你的 API Key 或其他敏感凭据信息。</p><h2 id="性能问题" tabindex="-1">性能问题 <a class="header-anchor" href="#性能问题" aria-label="Permalink to &quot;性能问题&quot;">​</a></h2><h3 id="q-对话超过-100-条消息后变得很卡怎么办" tabindex="-1">Q: 对话超过 100 条消息后变得很卡怎么办？ <a class="header-anchor" href="#q-对话超过-100-条消息后变得很卡怎么办" aria-label="Permalink to &quot;Q: 对话超过 100 条消息后变得很卡怎么办？&quot;">​</a></h3><p>A: 优化建议：</p><ol><li><strong>创建新会话</strong>：将当前会话作为备份，新建会话继续对话</li><li><strong>使用上下文压缩</strong>：将早期对话压缩为摘要</li><li><strong>调整虚拟列表渲染</strong>：在设置中减小 <code>virtualListOverscan</code> 值</li><li><strong>启用 HTML 预览冻结</strong>：自动冻结非最新消息的 HTML 预览</li></ol><h3 id="q-生成速度太慢怎么办" tabindex="-1">Q: 生成速度太慢怎么办？ <a class="header-anchor" href="#q-生成速度太慢怎么办" aria-label="Permalink to &quot;Q: 生成速度太慢怎么办？&quot;">​</a></h3><p>A: 可能的优化方向：</p><ol><li><strong>选择更快的模型</strong>：如 GPT-4o-mini、Claude Haiku 等</li><li><strong>缩短 Max Tokens</strong>：减少单次生成的输出长度</li><li><strong>关闭流式平滑化</strong>：在渲染设置中关闭，可减少渲染开销</li><li><strong>检查网络延迟</strong>：使用更靠近服务端的代理节点</li></ol><h2 id="兼容性" tabindex="-1">兼容性 <a class="header-anchor" href="#兼容性" aria-label="Permalink to &quot;兼容性&quot;">​</a></h2><h3 id="q-支持哪些-ai-服务商" tabindex="-1">Q: 支持哪些 AI 服务商？ <a class="header-anchor" href="#q-支持哪些-ai-服务商" aria-label="Permalink to &quot;Q: 支持哪些 AI 服务商？&quot;">​</a></h3><p>A: 支持所有兼容 OpenAI API 格式的服务商，包括：</p><ul><li>OpenAI (GPT-4o, GPT-4o-mini 等)</li><li>Anthropic (Claude 系列)</li><li>Google (Gemini 系列)</li><li>SiliconFlow、DeepSeek、Moonshot 等国内服务商</li><li>以及任何兼容 OpenAI 代理格式的自部署服务</li></ul><h3 id="q-支持流式输出吗" tabindex="-1">Q: 支持流式输出吗？ <a class="header-anchor" href="#q-支持流式输出吗" aria-label="Permalink to &quot;Q: 支持流式输出吗？&quot;">​</a></h3><p>A: 默认开启流式输出。你可以在聊天设置 → UI 偏好中关闭它（不推荐，会降低响应速度感知）。</p><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="q-在哪里反馈问题或建议" tabindex="-1">Q: 在哪里反馈问题或建议？ <a class="header-anchor" href="#q-在哪里反馈问题或建议" aria-label="Permalink to &quot;Q: 在哪里反馈问题或建议？&quot;">​</a></h3><p>A: 项目的 GitHub 仓库是 <a href="https://github.com/miaotouy/aio-hub" target="_blank" rel="noreferrer">miaotouy/aio-hub</a>，你可以在 Issues 中提交反馈。</p><h3 id="q-如何为项目贡献代码" tabindex="-1">Q: 如何为项目贡献代码？ <a class="header-anchor" href="#q-如何为项目贡献代码" aria-label="Permalink to &quot;Q: 如何为项目贡献代码？&quot;">​</a></h3><p>A: 请参考项目的<a href="/guide/contribution-guide">贡献指南</a>和<a href="/guide/tool-registry-guide">开发文档</a>。</p>',54)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
